-- Check all categories and their video counts
SELECT c.name, c.is_premium, COUNT(v.id) as video_count 
FROM categories c 
LEFT JOIN videos v ON c.id = v.category_id 
GROUP BY c.id, c.name, c.is_premium
ORDER BY c.sort_order;

-- Check total videos
SELECT COUNT(*) as total_videos FROM videos;

-- Show breakdown
SELECT 'Za moto' as category, COUNT(*) as count FROM videos WHERE category_id = (SELECT id FROM categories WHERE name = 'Za moto')
UNION ALL
